import { curryN } from '../src/curryN'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("one at a time", curryN((a:number,b:number,c:number)=>a+b+c,3)(1)(2)(3), 6)
await check("all at once", curryN((a:number,b:number)=>a*b,2)(3,4), 12)
await check("partial split", curryN((a:number,b:number,c:number)=>a+b+c,3)(1,2)(3), 6)
await check("arity one", curryN((a:number)=>a+10,1)(5), 15)
await check("ignores extra", curryN((a:number,b:number)=>a+b,2)(1,2,3), 3)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
